import{_ as e,o as a,c as i,a2 as t}from"./chunks/framework.il0noOp3.js";const k=JSON.parse('{"title":"CAF/WAF Assessment Platform","description":"Run a read-only CAF/WAF assessment with AzureScout — architecture, every run mode, all 22 assessments, and minimum auth per scan type.","frontmatter":{"description":"Run a read-only CAF/WAF assessment with AzureScout — architecture, every run mode, all 22 assessments, and minimum auth per scan type."},"headers":[],"relativePath":"assessment.md","filePath":"assessment.md"}'),n={name:"assessment.md"};function r(l,s,o,d,p,h){return a(),i("div",null,[...s[0]||(s[0]=[t('<h1 id="caf-waf-assessment-platform" tabindex="-1">CAF/WAF Assessment Platform <a class="header-anchor" href="#caf-waf-assessment-platform" aria-label="Permalink to &quot;CAF/WAF Assessment Platform&quot;">​</a></h1><p>Introduced in <strong>v2.0.0</strong>, AzureScout can score a tenant against the Microsoft <strong>Cloud Adoption Framework (CAF)</strong> design areas and <strong>Well-Architected Framework (WAF)</strong> pillars — not just inventory it. The assessment is <strong>read-only</strong> end to end (ARM Reader at the management-group root, plus read-only Graph app permissions for a subset of scans — see <a href="./assessment-permissions.html">Auth &amp; permissions per scan type</a>).</p><div class="tip custom-block"><p class="custom-block-title">PowerShell 7 required</p><p>The assessment platform requires <strong>PowerShell 7</strong> (every script starts with <code>#Requires -Version 7.0</code>). The v1 inventory features (<code>Invoke-AzureScout</code>) still run on Windows PowerShell 5.1. Full details, including a module bootstrap gap you need to work around manually: <a href="./assessment-prerequisites.html">Assessment Prerequisites</a>.</p></div><h2 id="architecture-—-three-layers-json-on-disk" tabindex="-1">Architecture — three layers, JSON on disk <a class="header-anchor" href="#architecture-—-three-layers-json-on-disk" aria-label="Permalink to &quot;Architecture — three layers, JSON on disk&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>COLLECT  --collect.json--&gt;  ASSESS  --findings.json--&gt;  REPORT</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Each layer runs independently from its JSON input, so you can collect once and assess later, or re-render reports from an existing findings set without re-scanning.</p><table tabindex="0"><thead><tr><th>Layer</th><th>What it does</th></tr></thead><tbody><tr><td><strong>Collect</strong></td><td>Read-only Azure Resource Graph queries produce a normalized <code>collect.json</code>, including a per-domain <code>domains.*</code> namespace.</td></tr><tr><td><strong>Ingest</strong></td><td>Folds Azure Governance Visualizer, an ARG query pack, and Azure Advisor into the same <code>collect.json</code>.</td></tr><tr><td><strong>Assess</strong></td><td>A declarative rule engine grades the collected data — <strong>139 rules across 8 CAF design areas + 5 WAF pillars</strong> — producing scored <code>findings.json</code> with a prioritized gap list.</td></tr><tr><td><strong>Report</strong></td><td>Renders <code>findings.json</code> into tiered deliverables.</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">Collect runs the full query set every time</p><p><code>Invoke-Collect.ps1</code> accepts a <code>-Categories</code> parameter (and <code>Invoke-ScoutAssessment</code> passes each assessment&#39;s declared <code>Collect</code> list, or your <code>-Category</code> override, into it), but in the current implementation that value is recorded into <code>collect.json</code>&#39;s <code>_meta.categories</code> for provenance only — <strong>it does not filter which Resource Graph queries run.</strong> Every <code>Invoke-Collect</code> call executes the same fixed set of ~25 queries regardless of assessment or <code>-Category</code>. The practical effect: choosing <code>-Assessment Security</code> vs. <code>-Assessment LandingZone</code> changes which <strong>rules</strong> are scored and which <strong>ingestors</strong> run, not how much data Collect pulls. This is worth knowing if you were expecting <code>-Category</code> to shrink scan time the way it does for <code>Invoke-AzureScout</code> (see <a href="./category-filtering.html">Category Filtering</a>, which is the v1, module-loading-level behavior — different mechanism, not shared with the assessment platform).</p></div><h2 id="run-modes" tabindex="-1">Run modes <a class="header-anchor" href="#run-modes" aria-label="Permalink to &quot;Run modes&quot;">​</a></h2><p>Every discovery category is an independently runnable, tagged assessment — pass one, several, or <code>All</code> to <code>-Assessment</code>. All examples assume you&#39;ve installed and imported the module:</p><div class="language-powershell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Install once, from the PowerShell Gallery (current version 2.0.1)</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Install-Module</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Name AzureScout</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Or import from a local clone</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Import-Module</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> .</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">AzureScout.psd1</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><h3 id="full-landing-zone-assessment" tabindex="-1">Full landing-zone assessment <a class="header-anchor" href="#full-landing-zone-assessment" aria-label="Permalink to &quot;Full landing-zone assessment&quot;">​</a></h3><p>Scores all 8 CAF areas and all 5 WAF pillars in one run, against an ALZ benchmark diff.</p><div class="language-powershell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Invoke-ScoutAssessment</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Assessment LandingZone </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">OutputFormat All</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="single-category" tabindex="-1">Single category <a class="header-anchor" href="#single-category" aria-label="Permalink to &quot;Single category&quot;">​</a></h3><div class="language-powershell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Invoke-ScoutAssessment</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Assessment Security </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">OutputFormat Html</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="multiple-assessments-in-one-run" tabindex="-1">Multiple assessments in one run <a class="header-anchor" href="#multiple-assessments-in-one-run" aria-label="Permalink to &quot;Multiple assessments in one run&quot;">​</a></h3><div class="language-powershell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Invoke-ScoutAssessment</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Assessment Networking</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">,</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Security </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">OutputFormat Html</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Findings from both are combined into one <code>findings.json</code> and one set of reports for the run.</p><h3 id="every-assessment-all" tabindex="-1">Every assessment (<code>All</code>) <a class="header-anchor" href="#every-assessment-all" aria-label="Permalink to &quot;Every assessment (`All`)&quot;">​</a></h3><div class="language-powershell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Invoke-ScoutAssessment</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Assessment All </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">OutputFormat All</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><code>-Assessment All</code> expands to every key in <code>manifests/assessments.psd1</code> — currently <strong>22</strong> assessments (see the <a href="./design/assessment-registry.html">full registry</a>).</p><h3 id="collect-once-assess-later-collectonly-fromcollect" tabindex="-1">Collect once, assess later (<code>-CollectOnly</code> / <code>-FromCollect</code>) <a class="header-anchor" href="#collect-once-assess-later-collectonly-fromcollect" aria-label="Permalink to &quot;Collect once, assess later (`-CollectOnly` / `-FromCollect`)&quot;">​</a></h3><div class="language-powershell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Stop after Collect — writes collect.json and returns its path</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Invoke-ScoutAssessment</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Assessment LandingZone </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">CollectOnly</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Re-run Assess + Report from that saved collect.json, no re-scan</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Invoke-ScoutAssessment</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Assessment LandingZone </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">FromCollect .</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">output</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">20260720_101500</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">collect.json </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">OutputFormat PowerBi</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>Useful for iterating on rule changes or re-rendering a different output tier without re-querying Azure.</p><h3 id="permission-pre-flight-permissionaudit" tabindex="-1">Permission pre-flight (<code>-PermissionAudit</code>) <a class="header-anchor" href="#permission-pre-flight-permissionaudit" aria-label="Permalink to &quot;Permission pre-flight (`-PermissionAudit`)&quot;">​</a></h3><div class="language-powershell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Invoke-ScoutAssessment</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Assessment LandingZone</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">,</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Identity </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">PermissionAudit</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Checks read-only access for the requested assessment(s) <strong>before</strong> any collection runs — see <a href="./assessment-permissions.html">Auth &amp; permissions per scan type</a> for exactly what this does and does not verify.</p><h3 id="scoping-to-a-management-group-managementgroupid" tabindex="-1">Scoping to a management group (<code>-ManagementGroupId</code>) <a class="header-anchor" href="#scoping-to-a-management-group-managementgroupid" aria-label="Permalink to &quot;Scoping to a management group (`-ManagementGroupId`)&quot;">​</a></h3><div class="language-powershell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Invoke-ScoutAssessment</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Assessment LandingZone </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ManagementGroupId </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;contoso-root-mg&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">OutputFormat Html</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><div class="warning custom-block"><p class="custom-block-title">Only scopes the AzGovViz ingest, not Collect</p><p><code>-ManagementGroupId</code> is passed straight through to <code>Import-AzGovViz</code>, which needs it to invoke the Azure Governance Visualizer. It is <strong>not</strong> used by <code>Invoke-Collect</code> to scope the Resource Graph queries — those already run tenant-wide against whatever subscriptions your authenticated context can see (no <code>-Subscription</code>/<code>-ManagementGroup</code> filter is ever passed to <code>Search-AzGraph</code>). For the 5 assessments that ingest AzGovViz (<code>LandingZone</code>, <code>Management</code>, <code>Identity</code>, <code>Governance</code>, <code>Policy</code>), omitting <code>-ManagementGroupId</code> doesn&#39;t error — it silently skips the ingest and governance rules degrade to <code>Unknown</code>. See <a href="./assessment-permissions.html#-managementgroupid-and-the-azgovviz-only-assessments">Auth &amp; permissions per scan type</a>.</p></div><h3 id="scope" tabindex="-1"><code>-Scope</code> <a class="header-anchor" href="#scope" aria-label="Permalink to &quot;`-Scope`&quot;">​</a></h3><div class="language-powershell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Invoke-ScoutAssessment</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Assessment LandingZone </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Scope All        </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># default</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Invoke-ScoutAssessment</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Assessment LandingZone </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Scope ArmOnly</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Invoke-ScoutAssessment</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Assessment LandingZone </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Scope EntraOnly</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><div class="info custom-block"><p class="custom-block-title">Ambiguity flagged, not guessed</p><p><code>-Scope</code> is accepted (<code>ValidateSet &#39;All&#39;,&#39;ArmOnly&#39;,&#39;EntraOnly&#39;</code>) and forwarded to <code>Invoke-Collect</code>, which stores it in <code>_meta.scope</code> — but <code>Invoke-Collect</code> has no ARM-vs-Entra branch in its query logic today (it only ever runs Resource Graph / ARM queries; there is no Graph-based collection path in the Collect layer). Functionally, in the current code, changing <code>-Scope</code> does not change what Collect gathers. Treat it as reserved / forward-compatible rather than a working ARM/Entra toggle for the assessment platform specifically — this differs from <code>Invoke-AzureScout -Scope</code>, which does gate ARM vs. Entra extraction in the v1 inventory tool (see <a href="./usage.html#scope">Usage Guide</a>).</p></div><h3 id="category-override" tabindex="-1"><code>-Category</code> override <a class="header-anchor" href="#category-override" aria-label="Permalink to &quot;`-Category` override&quot;">​</a></h3><div class="language-powershell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Invoke-ScoutAssessment</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Assessment Compute </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Category Compute</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">,</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Storage</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><code>-Category</code> replaces the categories recorded for the run rather than adding to the chosen assessment&#39;s own <code>Collect</code> list — but per the note above, it does not change what Collect actually queries (everything runs regardless), and it never changes which <strong>rules</strong> are scored (<code>Compute</code>&#39;s <code>Rules</code> stay <code>waf.reliability</code>/<code>waf.cost</code>/<code>waf.performance</code> no matter what <code>-Category</code> you pass). Prefer leaving <code>-Category</code> unset and letting each assessment use its own manifest-declared <code>Collect</code> list unless you have a specific provenance reason to override it.</p><h3 id="outputformat-—-one-example-per-tier" tabindex="-1"><code>-OutputFormat</code> — one example per tier <a class="header-anchor" href="#outputformat-—-one-example-per-tier" aria-label="Permalink to &quot;`-OutputFormat` — one example per tier&quot;">​</a></h3><div class="language-powershell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Invoke-ScoutAssessment</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Assessment LandingZone </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">OutputFormat PowerBi</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Invoke-ScoutAssessment</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Assessment LandingZone </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">OutputFormat Html</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Invoke-ScoutAssessment</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Assessment LandingZone </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">OutputFormat Pptx</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Invoke-ScoutAssessment</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Assessment LandingZone </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">OutputFormat Excel</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Invoke-ScoutAssessment</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Assessment LandingZone </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">OutputFormat Json</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Invoke-ScoutAssessment</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Assessment LandingZone </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">OutputFormat All     </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># PowerBi, Html, Pptx, Excel, Json</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p><code>-OutputFormat</code> also accepts an array (<code>-OutputFormat Html,Pptx</code>).</p><h3 id="outputpath" tabindex="-1"><code>-OutputPath</code> <a class="header-anchor" href="#outputpath" aria-label="Permalink to &quot;`-OutputPath`&quot;">​</a></h3><div class="language-powershell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Invoke-ScoutAssessment</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Assessment LandingZone </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">OutputPath </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;D:\\Reports\\Scout&#39;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Each run writes into a timestamped subfolder (<code>&lt;OutputPath&gt;/yyyyMMdd_HHmmss/</code>).</p><h2 id="all-22-assessments" tabindex="-1">All 22 assessments <a class="header-anchor" href="#all-22-assessments" aria-label="Permalink to &quot;All 22 assessments&quot;">​</a></h2><p>The full catalogue — description, <code>Collect</code>/<code>Ingest</code>, CAF areas / WAF pillars, and default report tiers, generated from <code>manifests/assessments.psd1</code> — lives in the <strong><a href="./design/assessment-registry.html">Assessment Registry</a></strong>. Minimum auth per assessment lives in <strong><a href="./assessment-permissions.html">Auth &amp; permissions per scan type</a></strong>.</p><h2 id="scoring" tabindex="-1">Scoring <a class="header-anchor" href="#scoring" aria-label="Permalink to &quot;Scoring&quot;">​</a></h2><ul><li>Each rule evaluates to <strong>Pass</strong>, <strong>Fail</strong>, <strong>Partial</strong>, <strong>Manual</strong>, <strong>Unknown</strong>, or <strong>Error</strong>.</li><li>Framework scores are the rule-count-weighted roll-up of area/pillar scores.</li><li><code>Unknown</code>/<code>Error</code> are surfaced, never silently dropped — a broken rule cannot inflate a score.</li><li>The <strong><code>Manual</code></strong> status intentionally hands the un-automatable checks to a human, with the collected evidence already attached.</li></ul><h2 id="report-tiers" tabindex="-1">Report tiers <a class="header-anchor" href="#report-tiers" aria-label="Permalink to &quot;Report tiers&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Tier</th><th>Output</th><th>Notes</th></tr></thead><tbody><tr><td>Power BI</td><td><code>powerbi/*.csv</code> + <code>.pbit</code></td><td>Primary analytics tier (star schema)</td></tr><tr><td>HTML</td><td><code>report.html</code></td><td>Self-contained, single file</td></tr><tr><td>PowerPoint</td><td><code>assessment_deck.pptx</code></td><td>Executive deck via the OpenXML SDK — <strong>no Python dependency</strong>. First use needs the <code>dotnet</code> SDK; see <a href="./assessment-prerequisites.html#powerpoint-tier-net-sdk-not-python">Assessment Prerequisites</a>.</td></tr><tr><td>Excel</td><td><code>assessment_evidence.xlsx</code></td><td>Evidence tier</td></tr><tr><td>JSON</td><td><code>findings.json</code></td><td>The machine-readable contract</td></tr></tbody></table><h2 id="minimum-auth-per-scan-type" tabindex="-1">Minimum auth per scan type <a class="header-anchor" href="#minimum-auth-per-scan-type" aria-label="Permalink to &quot;Minimum auth per scan type&quot;">​</a></h2><ul><li><strong>Every assessment</strong> needs <strong>ARM <code>Reader</code> at the tenant-root management group</strong>. No exceptions.</li><li><strong>Only 5 assessments</strong> additionally need Microsoft Graph <strong>application</strong> permissions — the ones whose <code>Ingest</code> includes <code>AzGovViz</code>: <code>LandingZone</code>, <code>Management</code>, <code>Identity</code>, <code>Governance</code>, <code>Policy</code>.</li><li>All other 17 assessments need <strong>ARM Reader only</strong> — no Graph permission at all.</li><li><code>PrivilegedAccess.Read.AzureResources</code> needs an <strong>Entra ID P2 license</strong> and is currently never exercised anyway — <code>Import-AzGovViz.ps1</code> unconditionally passes <code>-NoPIMEligibility</code>.</li></ul><p>Full matrix, the exact permissions list, and what <code>-PermissionAudit</code> does and does not verify: <strong><a href="./assessment-permissions.html">Auth &amp; permissions per scan type</a></strong>.</p><div class="language-powershell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Pre-flight before any collection runs</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Invoke-ScoutAssessment</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Assessment LandingZone </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">PermissionAudit</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h2 id="design-reference" tabindex="-1">Design reference <a class="header-anchor" href="#design-reference" aria-label="Permalink to &quot;Design reference&quot;">​</a></h2><p>The full architecture, rule catalogue, and decision records live in the <a href="./design/master-plan.html">Master Design &amp; Plan</a> and the <a href="./design/assessment-registry.html">assessment registry</a>.</p>',55)])])}const u=e(n,[["render",r]]);export{k as __pageData,u as default};
